// ===== JOB SEARCH CONFIG (ROLE-SPLIT WORKFLOW) =====
// Scope: role_leadership

const roleKeywords = [
  'Head of AI',
  'Head of Automation',
  'Head of AI Strategy',
  'Director of AI',
  'Director of Intelligent Automation',
  'Director of Automation',
  'Director of AI Platform',
  'Director of Digital Transformation',
  'Director Enterprise AI',
  'Director AI Governance'
];

const config = {
  workflowScope: 'role_leadership',

  indeedSearches: [],

  locationPlans: [
    {
      planId: 'ny_remote_hybrid',
      location: 'New York City Metropolitan Area',
      workTypes: ['remote', 'hybrid']
    },
    {
      planId: 'us_remote_only',
      location: 'United States',
      workTypes: ['remote']
    }
  ],

  datePosted: 'past_24h',
  maxResultsPerSearch: 40,
  includeComparisonWindow: false,
  comparisonDatePosted: 'past_week',
  comparisonMaxResults: 40,

  fetchFullDescription: true,
  enrichWithAI: false,
  linkedinCookie: $env.LINKEDIN_COOKIE || '',
  actorProxyConfig: {},

  runGuardEnabled: true,
  runGuardMinMinutes: 45,

  maxQueriesPerRun: 10,

  // Safe mode (KEPT)
  safeMode: false,
  safeMaxQueries: 2,
  safeMaxResults: 10,
  safeFetchFullDescription: false,

  testMode: false,
  testMaxQueries: 2,
  testMaxResults: 10,
  testFetchFullDescription: false,

  freshnessDays: 14,

  scoring: {
    titleKeywords: [
      'Head of AI',
      'Head of Automation',
      'Head of AI Strategy',
      'Director of AI',
      'Director of Intelligent Automation',
      'Director of Automation',
      'Director of AI Platform',
      'Director of Digital Transformation',
      'Director Enterprise AI',
      'Director AI Governance'
    ],
    partialKeywords: [
      'automation', 'workflow', 'ai', 'agentic', 'rpa', 'intelligent automation',
      'hyperautomation', 'power platform', 'power automate', 'servicenow',
      'integration', 'ipaas', 'workato', 'mulesoft', 'boomi', 'zapier', 'make', 'n8n'
    ],
    seniorityWords: [
      'chief', 'vp', 'vice president', 'director', 'head of', 'senior director',
      'principal', 'lead', 'architect'
    ],
    nycAreaKeywords: [
      'new york', 'nyc', 'newburgh', 'poughkeepsie', 'hudson valley',
      'westchester', 'stamford', 'jersey city', 'newark', 'white plains',
      'yonkers', 'brooklyn', 'manhattan', 'bronx', 'queens', 'staten island'
    ],
    aiGovernanceKeywords: [
      'ai governance', 'ai adoption', 'ai strategy', 'ai policy',
      'responsible ai', 'ai ethics', 'ai transformation', 'ai roadmap',
      'generative ai', 'enterprise ai'
    ],
    londonKeywords: [
      'london', 'united kingdom', ', uk', ', england', 'greater london'
    ],
    highRelevanceThreshold: 60
  },

  airtableBaseId: 'appHQJJBGSLIXybkr',
  airtableTableId: 'tbltkycOY9FgUdQpm',
  airtableApiKey: '{{ $credentials.airtableApiKey }}',

  slackWebhookUrl: $env.SLACK_WEBHOOK_URL || '',
  telegramBotToken: '{{ $credentials.telegramBotToken }}',
  telegramChatId: '6592429185'
};

const primarySearches = [];
for (const keywords of roleKeywords) {
  for (const plan of config.locationPlans) {
    for (const workType of plan.workTypes) {
      primarySearches.push({
        keywords,
        location: plan.location,
        workType,
        datePosted: config.datePosted,
        maxResults: config.maxResultsPerSearch,
        scope: config.workflowScope,
        planId: plan.planId,
        windowId: 'primary'
      });
    }
  }
}

const comparisonSearches = [];
if (config.includeComparisonWindow) {
  for (const keywords of roleKeywords) {
    for (const plan of config.locationPlans) {
      for (const workType of plan.workTypes) {
        comparisonSearches.push({
          keywords,
          location: plan.location,
          workType,
          datePosted: config.comparisonDatePosted,
          maxResults: config.comparisonMaxResults,
          scope: config.workflowScope,
          planId: plan.planId,
          windowId: 'comparison'
        });
      }
    }
  }
}

config.linkedinSearches = [...primarySearches, ...comparisonSearches];
const maxQueriesPerRun = Math.max(1, Number(config.maxQueriesPerRun ?? 10));
config.linkedinSearches = config.linkedinSearches.slice(0, maxQueriesPerRun);

const effectiveSafeMode = !!(config.safeMode || config.testMode);
if (effectiveSafeMode) {
  const maxQueries = Math.max(1, Number(config.safeMaxQueries ?? config.testMaxQueries ?? 1));
  const maxResults = Math.max(1, Number(config.safeMaxResults ?? config.testMaxResults ?? 10));
  const safeFetch = (config.safeFetchFullDescription ?? config.testFetchFullDescription ?? false);

  config.linkedinSearches = config.linkedinSearches
    .slice(0, maxQueries)
    .map(search => ({ ...search, maxResults: Math.min(Number(search.maxResults || 40), maxResults) }));

  config.fetchFullDescription = !!safeFetch;
}

config._abortRun = false;
config._abortReason = '';

try {
  const staticData = $getWorkflowStaticData('global');
  const nowMs = Date.now();
  const minGapMs = Math.max(1, Number(config.runGuardMinMinutes || 45)) * 60 * 1000;
  const runGuardKey = `linkedinScraperLastStartMs_${config.workflowScope}`;
  const lastStartMs = Number(staticData[runGuardKey] || 0);

  if (config.runGuardEnabled && lastStartMs && (nowMs - lastStartMs) < minGapMs) {
    const elapsedMinutes = Math.floor((nowMs - lastStartMs) / 60000);
    const waitMinutes = Math.ceil((minGapMs - (nowMs - lastStartMs)) / 60000);
    config._abortRun = true;
    config._abortReason = `Blocked by run guard: last run started ${elapsedMinutes} minute(s) ago. Try again in about ${waitMinutes} minute(s).`;
  } else {
    staticData[runGuardKey] = nowMs;
  }
} catch (error) {
  config._abortRun = false;
  config._abortReason = `Run guard unavailable: ${error?.message || String(error)}`;
}

return [{ json: config }];

// Split LinkedIn searches into individual items
const config = $input.first().json;

if (config._abortRun) {
  console.log(config._abortReason || 'Run aborted by guard.');
  return [];
}

const scope = config.workflowScope || 'default';
const staticData = $getWorkflowStaticData('global');

// Guard 1: never emit twice within the same execution
const execGuardKey = `splitLastExecutionId_${scope}`;
const currentExecutionId = String($execution.id || '');
if (staticData[execGuardKey] === currentExecutionId) {
  return [];
}
staticData[execGuardKey] = currentExecutionId;

const searches = Array.isArray(config.linkedinSearches) ? config.linkedinSearches : [];

// Safety dedupe in case upstream config accidentally repeats query tuples
const seen = new Set();
const uniqueSearches = [];
for (const search of searches) {
  const key = [
    search.keywords,
    search.location,
    search.workType,
    search.datePosted,
    search.windowId || 'primary'
  ]
    .map(v => String(v || '').toLowerCase().trim())
    .join('|');

  if (seen.has(key)) continue;
  seen.add(key);
  uniqueSearches.push(search);
}

// Guard 2 (global fail-safe): max 10 actor calls per role per 15-minute window
const HARD_MAX_QUERIES = 10;
const BUDGET_WINDOW_MINUTES = 15;
const budgetKey = `splitBudget_${scope}`;
const now = Date.now();
let budget = staticData[budgetKey] || { windowStartMs: now, count: 0 };

const windowMs = BUDGET_WINDOW_MINUTES * 60 * 1000;
if (!budget.windowStartMs || (now - Number(budget.windowStartMs)) >= windowMs) {
  budget = { windowStartMs: now, count: 0 };
}

const configuredMax = Math.max(1, Number(config.maxQueriesPerRun ?? HARD_MAX_QUERIES));
const remainingBudget = Math.max(0, HARD_MAX_QUERIES - Number(budget.count || 0));
const effectiveMax = Math.min(HARD_MAX_QUERIES, configuredMax, remainingBudget);

if (effectiveMax <= 0) {
  return [];
}

const finalSearches = uniqueSearches.slice(0, effectiveMax);

budget.count = Number(budget.count || 0) + finalSearches.length;
staticData[budgetKey] = budget;

return finalSearches.map((search, idx) => ({
  json: {
    ...search,
    _queryIndex: idx + 1,
    _queryCount: finalSearches.length,
    fetchFullDescription: typeof search.fetchFullDescription === 'boolean'
      ? search.fetchFullDescription
      : !!config.fetchFullDescription,
    enrichWithAI: !!config.enrichWithAI,
    linkedinCookie: config.linkedinCookie || '',
    actorProxyConfig: config.actorProxyConfig || {},
    _config: config,
  }
}));

// Normalize Mfrostbutter/linkedin-jobs-scraper output to unified job schema
const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;
  // Our actor always emits title + companyName; skip empty records
  if (!d || !d.title) continue;

  const loc = d.location || '';
  const workplaceType = d.workRemoteAllowed
    ? (d.workplaceTypes && d.workplaceTypes[0]) || 'Remote'
    : 'On-site';

  // salary_low/salary_high come from parser; salary is the raw string
  let salaryMin = d.salary_low || null;
  let salaryMax = d.salary_high || null;

  // Carry config forward when available. Actor dataset items usually drop upstream fields,
  // so fallback to Config node when this workflow path includes it.
  let cfg = item.json._config;
  if (!cfg) {
    try {
      cfg = $('Config').first()?.json || null;
    } catch (e) {
      cfg = null;
    }
  }

  results.push({
    jobTitle: d.title || '',
    company: d.companyName || '',
    location: loc,
    source: 'LinkedIn',
    sourceId: d.id || `li-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    sourceUrl: d.link || d.applyUrl || '',
    postedDate: d.postedAt || new Date().toISOString(),
    salaryMin: salaryMin,
    salaryMax: salaryMax,
    employmentType: 'Full-time',
    workplaceType: workplaceType,
    companySize: '',
    companyIndustry: '',
    descriptionSnippet: (d.descriptionText || '').substring(0, 500),
    fullDescription: d.descriptionText || '',
    easyApply: false,
    applicants: null,
    _config: cfg,
  });
}

return results.map(r => ({ json: r }));

// ===== DEDUP + SCORE =====
// Deduplicates within batch and scores each job for relevance.

const items = $input.all();

const DEFAULT_SCORING = {
  titleKeywords: [
    'technology director', 'cio', 'chief ai officer', 'caio',
    'it director', 'director ai governance', 'ai adoption',
    'chief information officer', 'vp technology', 'head of ai',
    'principal ai engineer', 'solutions architect', 'solutions engineer',
    'director of ai'
  ],
  partialKeywords: [
    'ai', 'artificial intelligence', 'automation', 'digital transformation',
    'governance', 'machine learning', 'technology', 'architect', 'principal'
  ],
  seniorityWords: [
    'chief', 'vp', 'vice president', 'director', 'head of', 'senior director',
    'cio', 'cto', 'caio', 'principal', 'staff', 'lead'
  ],
  nycAreaKeywords: [
    'new york', 'nyc', 'newburgh', 'poughkeepsie', 'hudson valley',
    'westchester', 'stamford', 'jersey city', 'newark', 'white plains',
    'yonkers', 'brooklyn', 'manhattan', 'bronx', 'queens', 'staten island'
  ],
  aiGovernanceKeywords: [
    'ai governance', 'ai adoption', 'ai strategy', 'ai policy',
    'responsible ai', 'ai ethics', 'ai transformation', 'ai roadmap',
    'generative ai', 'enterprise ai'
  ],
  londonKeywords: ['london', 'united kingdom', ', uk', ', england', 'greater london'],
  highRelevanceThreshold: 60,
};

function getScoringConfig() {
  const fromItem = items[0]?.json?._config?.scoring;
  if (fromItem && typeof fromItem === 'object') return fromItem;
  return DEFAULT_SCORING;
}

const config = getScoringConfig();

// Dedup within batch by normalized title + company
const seen = new Set();
const unique = [];
for (const item of items) {
  const d = item.json;
  const key = `${(d.jobTitle || '').toLowerCase().trim()}|${(d.company || '').toLowerCase().trim()}`;
  if (seen.has(key)) continue;
  seen.add(key);
  unique.push(d);
}

// Scoring function
function scoreJob(job) {
  let score = 0;
  const breakdown = [];
  const titleLower = (job.jobTitle || '').toLowerCase();
  const descLower = (job.fullDescription || '').toLowerCase();

  // Title exact match (+30)
  const exactMatch = config.titleKeywords.some(kw => titleLower.includes(kw));
  if (exactMatch) {
    score += 30;
    breakdown.push('Title exact match: +30');
  } else {
    // Partial keyword match (+15)
    const hasPartial = config.partialKeywords.some(kw => titleLower.includes(kw));
    if (hasPartial) {
      score += 15;
      breakdown.push('Title partial match: +15');
    }
  }

  // Seniority signal (+5)
  if (config.seniorityWords.some(w => titleLower.includes(w))) {
    score += 5;
    breakdown.push('Senior title: +5');
  }

  // Location: Remote/Hybrid (+20), NYC metro (+15)
  const locLower = (job.location || '').toLowerCase();
  const wpLower = (job.workplaceType || '').toLowerCase();
  if (wpLower.includes('remote') || locLower.includes('remote')) {
    score += 20;
    breakdown.push('Remote: +20');
  } else if (wpLower.includes('hybrid') || locLower.includes('hybrid')) {
    score += 20;
    breakdown.push('Hybrid: +20');
  } else if (config.nycAreaKeywords.some(kw => locLower.includes(kw))) {
    score += 15;
    breakdown.push('NYC metro area: +15');
  }

  // Salary >= $150K (+10)
  if (job.salaryMin && job.salaryMin >= 150000) {
    score += 10;
    breakdown.push('Salary >= $150K: +10');
  } else if (job.salaryMax && job.salaryMax >= 150000) {
    score += 5;
    breakdown.push('Salary range includes $150K+: +5');
  }

  // Mid-market company 100-2000 employees (+10)
  const sizeStr = (job.companySize || '').replace(/,/g, '');
  const sizeMatch = sizeStr.match(/(\d+)/);
  if (sizeMatch) {
    const size = parseInt(sizeMatch[1]);
    if (size >= 100 && size <= 2000) {
      score += 10;
      breakdown.push('Mid-market company (100-2K): +10');
    } else if (size > 2000 && size <= 10000) {
      score += 5;
      breakdown.push('Large company (2K-10K): +5');
    }
  }

  // AI governance/adoption keywords in description (+10)
  const hasGovernance = config.aiGovernanceKeywords.some(kw => descLower.includes(kw));
  if (hasGovernance) {
    score += 10;
    breakdown.push('AI governance/adoption match: +10');
  }

  // Negative signals (-20)
  if (titleLower.match(/\b(intern|junior|entry.level|associate|analyst)\b/)) {
    score -= 20;
    breakdown.push('Junior/entry role: -20');
  }

  return {
    relevanceScore: Math.max(0, Math.min(100, score)),
    scoreBreakdown: JSON.stringify(breakdown),
    isHighRelevance: score >= config.highRelevanceThreshold,
    aiGovernanceMatch: hasGovernance
  };
}

// Score each job
const scored = unique.map(job => {
  const scores = scoreJob(job);
  return {
    json: {
      ...job,
      ...scores,
      firstSeen: new Date().toISOString(),
      lastSeen: new Date().toISOString(),
      status: 'New'
    }
  };
});

// Sort by relevance score descending
scored.sort((a, b) => b.json.relevanceScore - a.json.relevanceScore);

// ===== DUAL NY+LONDON OFFICE DETECTION =====
const londonKws = config.londonKeywords || ['london', 'united kingdom', ', uk', ', england', 'greater london'];

const companiesByRegion = {};
for (const item of scored) {
  const company = (item.json.company || '').toLowerCase().trim();
  if (!company) continue;
  const loc = (item.json.location || '').toLowerCase();
  const isLondon = londonKws.some(kw => loc.includes(kw));
  const isNY = config.nycAreaKeywords.some(kw => loc.includes(kw));
  if (!companiesByRegion[company]) companiesByRegion[company] = { ny: false, london: false };
  if (isLondon) companiesByRegion[company].london = true;
  if (isNY) companiesByRegion[company].ny = true;
}

for (const item of scored) {
  const company = (item.json.company || '').toLowerCase().trim();
  const isDual = !!(companiesByRegion[company] && companiesByRegion[company].ny && companiesByRegion[company].london);
  item.json.dualOfficeNYLondon = isDual;
  if (isDual) {
    item.json.relevanceScore = Math.min(100, item.json.relevanceScore + 15);
    const breakdown = JSON.parse(item.json.scoreBreakdown || '[]');
    breakdown.push('Dual NY+London office: +15');
    item.json.scoreBreakdown = JSON.stringify(breakdown);
  }
}

// Re-sort after dual-office bonus
scored.sort((a, b) => b.json.relevanceScore - a.json.relevanceScore);

return scored;

const items = $input.all();

let cfg = items[0]?.json?._config || null;
if (!cfg) { try { cfg = $('Dedup and Score').first()?.json?._config || null; } catch {} }

const slackWebhookUrl = cfg?.slackWebhookUrl || $env.SLACK_WEBHOOK_URL || '';

let succeeded = 0;
let rateLimited = 0;
let otherFailed = 0;
for (const i of items) {
  const j = i.json || {};
  if (j.records && j.records[0] && j.records[0].id) succeeded += 1;
  else if (Array.isArray(j.errors) && j.errors.some(e => (e.error||'').includes('RATE_LIMIT'))) rateLimited += 1;
  else if (j.errors || j.error) otherFailed += 1;
}
const total = items.length;
const count = succeeded;

let message;
if (total === 0) {
  message = 'No new jobs added.';
} else if (rateLimited === 0 && otherFailed === 0) {
  message = `New jobs have been added to Airtable. (${succeeded})`;
} else {
  message = `Airtable: ${succeeded} added, ${rateLimited} rate-limited, ${otherFailed} other failed (out of ${total}).`;
}

return [{ json: { message, count, succeeded, rateLimited, otherFailed, total, slackWebhookUrl } }];

// Trigger Workflow 2 (Resume Generator) for high-scoring new jobs
// Only for jobs scoring >= 70
const items = $('Create Airtable Record').all();
const toGenerate = items.filter(item => {
  const score = item.json.records?.[0]?.fields?.['Relevance Score'] || 0;
  return score >= 70;
});

if (toGenerate.length === 0) {
  return [];
}

const webhookUrl = 'https://n8n-dev.ageniuslabs.com/webhook/job-resume-generator';
const triggered = [];

for (const item of toGenerate) {
  const f = item.json.records?.[0]?.fields || {};
  const recordId = item.json.records?.[0]?.id || '';
  triggered.push({
    airtableRecordId: recordId,
    jobTitle: f['Job Title'],
    company: f['Company'],
    fullDescription: f['Full Description'],
    sourceUrl: f['Source URL'],
    source: f['Source']
  });
}

return triggered.map(t => ({ json: { ...t, webhookUrl } }));

